arguments:
{"script":"file=/usr/stock.log
if [ ! -r "$file" ]; then echo "0"; exit 0; fi
awk '
{
  l=tolower($0);
  if(index(l,"alice")==0) next;
  sold=0;
  if(match(l, "sell")) sold=1;
  c = $(NF) + 0;
  if(c < 0) sold=1;
  if(NF>=3){
    a=tolower($(NF-2));
    if(a=="sell"||a=="sold"||a=="s") sold=1;
  }
  if(sold) print NR;
}' "$file" | sort -n | uniq | wc -l
"}
